// // This module implements a 4-bit shift register with serial input and parallel output. On each positive clock edge, the shift register shifts its contents to the right instead of the left, and the new bit shifted in from the right is the serial input.
module shift_register_4bit(
    input clk,
    input rst,
    input serial_in,

    output reg [3:0] parallel_out
);
    always @(posedge clk or posedge rst) begin
        if (rst) 
            parallel_out <= 4'b0000;
        else 
            parallel_out <= {parallel_out[2:0], serial_in};
    end
endmodule
